svg.script:
(function(){
const S={hp:110,engWeight:320,matWeight:58,matStrength:58,control:new Set(),torque:'none'};
const $=id=>document.getElementById(id);
function textLines(text,width,fontSize){const maxChars=Math.max(8,Math.floor(width/(fontSize*.55)));const words=String(text).split(/\s+/);let lines=[],line='';for(const w of words){const test=line?line+' '+w:w;if(test.length<=maxChars){line=test}else{if(line)lines.push(line);line=w}}if(line)lines.push(line);return lines}
function wrapText(el,text){const width=Number(el.getAttribute('data-wrap')||0);if(!width)return;if(text!==undefined&&!el.getAttribute('data-raw'))el.setAttribute('data-raw',text);const raw=text!==undefined?text:(el.getAttribute('data-raw')||el.textContent);const cls=el.getAttribute('class')||'';const fs=cls.includes('h2')?24:cls.includes('h3')?20:cls.includes('value')?20:cls.includes('tiny')?13:cls.includes('callout')?17:16;const lh=fs*1.35;const x=el.getAttribute('x')||0;const y=el.getAttribute('y')||0;el.textContent='';textLines(raw,width,fs).forEach((line,i)=>{const t=document.createElementNS('http://www.w3.org/2000/svg','tspan');t.setAttribute('x',x);t.setAttribute('dy',i?lh:0);if(!i)t.setAttribute('y',y);t.textContent=line;el.appendChild(t)});}
function wrapAll(){document.querySelectorAll('text[data-wrap]').forEach(el=>wrapText(el,el.getAttribute('data-raw')||el.textContent));}
function clamp(v,a,b){return Math.max(a,Math.min(b,v))}
function colorScore(score){return score>78?'#83f29b':score>52?'#ffe066':'#ff6961'}
function setText(id,t){const e=$(id); if(!e)return; if(e.hasAttribute('data-wrap')){e.setAttribute('data-raw',t);wrapText(e,t);} else e.textContent=t}
function setAttrs(id,o){const e=$(id); if(e)Object.entries(o).forEach(([k,v])=>e.setAttribute(k,v))}
const sliders={hp:{min:45,max:260,len:360,x:34,y:128,w:360,fill:'hpFill',knob:'hpKnob',val:'hpVal',fmt:v=>Math.round(v)+' hp'},engWeight:{min:120,max:620,len:360,x:34,y:248,w:360,fill:'engWeightFill',knob:'engWeightKnob',val:'engWeightVal',fmt:v=>Math.round(v)+' lb'},matWeight:{min:10,max:100,len:380,x:34,y:120,w:380,fill:'matWeightFill',knob:'matWeightKnob',val:'matWeightVal',fmt:v=>'density index '+Math.round(v)},matStrength:{min:10,max:100,len:380,x:34,y:240,w:380,fill:'matStrengthFill',knob:'matStrengthKnob',val:'matStrengthVal',fmt:v=>'strength index '+Math.round(v)}};
function updateSlider(id){const c=sliders[id],v=S[id],p=(v-c.min)/(c.max-c.min),x=p*c.len; setAttrs(c.fill,{x2:x}); setAttrs(c.knob,{cx:x}); setText(c.val,c.fmt(v));}
function sliderFromEvent(g,evt){const id=g.getAttribute('data-id'),c=sliders[id],pt=document.documentElement.createSVGPoint(); const src=evt.touches?evt.touches[0]:evt; pt.x=src.clientX; pt.y=src.clientY; const m=g.getScreenCTM().inverse(); const loc=pt.matrixTransform(m); const p=clamp(loc.x/c.len,0,1); S[id]=c.min+p*(c.max-c.min); updateSlider(id); updateAll();}
document.querySelectorAll('.slider').forEach(g=>{let drag=false; const start=e=>{drag=true; sliderFromEvent(g,e); e.preventDefault()}; const move=e=>{if(drag){sliderFromEvent(g,e); e.preventDefault()}}; const end=()=>drag=false; g.addEventListener('mousedown',start); window.addEventListener('mousemove',move); window.addEventListener('mouseup',end); g.addEventListener('touchstart',start,{passive:false}); window.addEventListener('touchmove',move,{passive:false}); window.addEventListener('touchend',end);});
document.querySelectorAll('.tab').forEach(t=>t.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));t.classList.add('active');document.querySelectorAll('.scene').forEach(s=>s.classList.remove('active'));$('scene-'+t.dataset.tab).classList.add('active');}));
const controlItems=[['collective','Collective pitch','All blades change pitch together for climb/descent.'],['cyclic','Cyclic pitch','Blade pitch changes around the circle to tilt the rotor disk.'],['swash','Swashplate','Transfers pilot input to spinning rotor blades.'],['tail','Tail rotor yaw','Helps point the nose and stop unwanted spin.'],['dampers','Dampers / hinges','Reduce vibration and control coupling.']];
const cb=$('controlButtons'); controlItems.forEach((it,i)=>{const g=document.createElementNS('http://www.w3.org/2000/svg','g');g.setAttribute('class','touchButton');g.setAttribute('transform',`translate(26,${72+i*54})`);g.dataset.id=it[0];g.innerHTML=`<rect rx="16" width="402" height="42" fill="#0a203a" stroke="#4b8fc1" stroke-width="2"/><text x="18" y="27" class="buttonText">+ ${it[1]}</text>`;g.addEventListener('click',()=>{S.control.has(it[0])?S.control.delete(it[0]):S.control.add(it[0]); updateControl();});cb.appendChild(g);});
const torqueItems=[['none','No anti-torque','Demonstrate the spin problem'],['tail','Tail rotor','Side thrust cancels main-rotor torque'],['coax','Coaxial rotors','Two rotors spin opposite directions'],['fins','Fins + stabilizer','Helpful in forward flight, weak in hover']];
const tb=$('torqueButtons'); torqueItems.forEach((it,i)=>{const g=document.createElementNS('http://www.w3.org/2000/svg','g');g.setAttribute('class','touchButton');g.setAttribute('transform',`translate(26,${75+i*60})`);g.dataset.id=it[0];g.innerHTML=`<rect rx="17" width="402" height="46" fill="#0a203a" stroke="#4b8fc1" stroke-width="2"/><text x="18" y="30" class="buttonText">${it[1]}</text>`;g.addEventListener('click',()=>{S.torque=it[0]; updateTorque();});tb.appendChild(g);});
function updatePower(){const total=520+S.engWeight; const pwr=S.hp/total; const score=clamp((pwr-.12)/(.34-.12)*100,0,100); setText('powerMath',pwr.toFixed(2)+' hp/lb → '+(score>72?'hover possible':score>45?'almost there':'not enough')); setAttrs('pwBar',{width:3.2*score,fill:colorScore(score)}); setText('pwText',pwr.toFixed(2)+' hp/lb'); setAttrs('engineBlock',{width:70+(S.hp-45)/215*70,height:40+(S.engWeight-120)/500*40,fill:S.engWeight>420?'#ff6961':S.hp>180?'#83f29b':'#ffad5a'}); setAttrs('liftArrow',{opacity:.25+score/130,'stroke-width':6+score/9}); setAttrs('weightArrow',{opacity:.35+S.engWeight/900,'stroke-width':7+S.engWeight/70}); const craft=$('powerBody'); craft.setAttribute('class',score>72?'float':score>45?'wobble':'shake'); $('mainRotorPower').setAttribute('class',score>52?'fastRotor':'rotor'); setText('powerVerdict',score>72?'LIFT-OFF!':score>45?'Almost flies':'Too weak/heavy'); $('powerVerdict').setAttribute('class','h2 '+(score>72?'good':score>45?'warn':'bad')); setText('powerTip',score>72?'You found a practical power-to-weight window.':'Increase strength or reduce engine mass. Early designs struggled here.');}
function updateMaterials(){const specific=S.matStrength/(S.matWeight+8); const score=clamp((specific-.25)/(2.2-.25)*100,0,100); const heavy=S.matWeight>70, weak=S.matStrength<45; setAttrs('blade',{fill:score>74?'#bff7df':score>48?'#ffe8a0':'#d8e7f6',d:`M0 ${85+Math.max(0,S.matWeight-45)/4} C160 ${40+Math.max(0,S.matWeight-S.matStrength)/3} 350 ${45+Math.max(0,S.matWeight-S.matStrength)/2} 550 75 C585 80 588 115 552 120 C350 ${150+Math.max(0,S.matWeight-S.matStrength)/2} 160 ${145+Math.max(0,S.matWeight-S.matStrength)/3} 0 ${100+Math.max(0,S.matWeight-45)/4} Z`}); setAttrs('cracks',{opacity:weak?.95:0}); setText('bladeLabel',score>74?'Strong and light':score>48?'Promising, but risky':'Bends or breaks'); setText('matClass',score>74?'Composite-like sweet spot':heavy?'Old heavy structure':weak?'Too fragile':'Mixed early structure'); setText('matVerdict',score>74?'Succeeds: high strength-to-weight':'Fails: too heavy or too weak'); $('matVerdict').setAttribute('class','h2 '+(score>74?'good':score>48?'warn':'bad')); setText('matTip',score>74?'This mirrors why modern composites/alloys matter.':'Try lower density and higher strength/stiffness.');}
function updateControl(){document.querySelectorAll('#controlButtons .touchButton').forEach(g=>{const on=S.control.has(g.dataset.id);g.querySelector('rect').setAttribute('fill',on?'#1d5b8f':'#0a203a');g.querySelector('rect').setAttribute('stroke',on?'#76dcff':'#4b8fc1');}); let score=10; if(S.control.has('collective'))score+=16;if(S.control.has('cyclic'))score+=23;if(S.control.has('swash'))score+=21;if(S.control.has('tail'))score+=18;if(S.control.has('dampers'))score+=12; score=clamp(score,0,100); setAttrs('controlBar',{width:3.92*score,fill:colorScore(score)}); setText('controlPct',score+'%'); ['swashViz','pitchViz','collectViz','damperViz'].forEach(id=>setAttrs(id,{opacity:0})); if(S.control.has('swash'))setAttrs('swashViz',{opacity:1}); if(S.control.has('cyclic'))setAttrs('pitchViz',{opacity:1}); if(S.control.has('collective'))setAttrs('collectViz',{opacity:1}); if(S.control.has('dampers'))setAttrs('damperViz',{opacity:1}); $('controlCraft').setAttribute('class',score>80?'float':score>55?'wobble':'shake'); setText('controlVerdict',score>80?'Controlled flight':score>55?'Partly controllable':'Unstable hop'); $('controlVerdict').setAttribute('class','h2 '+(score>80?'good':score>55?'warn':'bad')); setText('controlExplain',score>80?'The craft can climb, tilt, yaw, and damp vibration instead of merely hopping.':'Add cyclic + collective + swashplate + yaw control + damping.');}
function updateTorque(){document.querySelectorAll('#torqueButtons .touchButton').forEach(g=>{const on=S.torque===g.dataset.id;g.querySelector('rect').setAttribute('fill',on?'#1d5b8f':'#0a203a');g.querySelector('rect').setAttribute('stroke',on?'#76dcff':'#4b8fc1');}); const score={none:8,tail:88,coax:92,fins:34}[S.torque]||8; setAttrs('torqueBar',{width:3.9*score,fill:colorScore(score)}); setText('torquePct',score+'%'); setAttrs('tailRotorViz',{opacity:S.torque==='tail'?1:0}); setAttrs('antiArrow',{opacity:S.torque==='tail'?1:0}); setAttrs('coaxRotor',{opacity:S.torque==='coax'?1:0}); setAttrs('singleRotor',{opacity:S.torque==='coax'?0:1}); setAttrs('spinArrow',{opacity:score>80?.18:.9}); $('torqueCraft').setAttribute('class',score>80?'float':score>45?'wobble':'shake'); setText('torqueVerdict',score>80?'Torque balanced':score>45?'Some stability, not enough':'Spins out'); $('torqueVerdict').setAttribute('class','h2 '+(score>80?'good':score>45?'warn':'bad')); setText('torqueExplain',S.torque==='tail'?'A tail rotor pushes sideways to oppose fuselage spin and control yaw.':S.torque==='coax'?'Counter-rotating rotors cancel much of each other’s torque.':S.torque==='fins'?'Fins help in forward motion, but hover still needs anti-torque control.':'Try a tail rotor or coaxial counter-rotating rotors to cancel torque.');}
function updateAll(){updatePower(); updateMaterials(); updateControl(); updateTorque();}
wrapAll(); Object.keys(sliders).forEach(updateSlider); updateAll();
})();
